<span class="line"><span style="color:#CDD6F4;">    directory</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> z</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">string</span><span style="color:#CDD6F4;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">default</span><span style="color:#CDD6F4;">(</span><span style="color:#A6E3A1;">&quot;.&quot;</span><span style="color:#CDD6F4;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">describe</span><span style="color:#CDD6F4;">(</span><span style="color:#A6E3A1;">&quot;Root directory&quot;</span><span style="color:#CDD6F4;">)</span><span style="color:#9399B2;">,</span></span>
